const item = $input.first().json;
const body = item.body || item.params || item;
let prompt = body.prompt || body.media_prompt || body.text || 'Mẫu váy thời trang cao cấp trên người mẫu';
const chatId = body.chat_id || body.chatId || body.telegram_chat_id || body.senderId || body.admin_chat_id;

const ratioMatch = prompt.match(/(1:1|3:4|4:5|9:16|16:9|2:3|3:2)/);
const aspectRatio = ratioMatch ? ratioMatch[0] : '3:4';

if (ratioMatch) {
  prompt = prompt.replace(ratioMatch[0], '').replace(/\s+/g, ' ').trim();
}

const isFashion = /váy|đầm|áo|quần|giày|mẫu|thời trang|fashion|dress|skirt|shirt|pants|model|wear|suit/i.test(prompt);
let finalPrompt = prompt;

if (isFashion) {
  finalPrompt = `Create a professional e-commerce fashion photo.
Subject: A realistic photo of a young, attractive Vietnamese model wearing: ${prompt}.
Pose & Expression: Standing in a natural, relaxed, and confident pose with a candid, pleasant expression.
Camera & Technique: Captured with a 35mm DSLR lens, shallow depth of field with soft bokeh background, subtle natural film grain, sharp focus on the clothing details.
Lighting: Warm natural daylight, soft shadows, no harsh studio flashes, natural reflections.
Background: A modern, minimalist café or elegant street corner that complements the outfit naturally without being distracting.
Output: One single high-resolution fashion photograph. No text overlay, watermark, price tag, or graphic borders.`;
}

return [{
  json: {
    prompt: finalPrompt,
    aspect_ratio: aspectRatio,
    chat_id: chatId,
    source: body.source || 'telegram'
  }
}];

