const response = $input.first().json;
const request = $node['Normalize Media Request'].json;

const parts = response.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find(p => p.inlineData?.data || p.inline_data?.data);
const inlineData = imagePart?.inlineData || imagePart?.inline_data;

if (!inlineData?.data) {
  throw new Error('Gemini không trả về ảnh. Parts: ' + JSON.stringify(parts.map(p => Object.keys(p))));
}

const mimeType = inlineData.mimeType || inlineData.mime_type || 'image/jpeg';
const base64Data = inlineData.data;
const ext = mimeType.includes('png') ? 'png' : 'jpg';

return [{
  json: {
    prompt: request.prompt,
    chat_id: request.chat_id,
    mime_type: mimeType
  },
  binary: {
    image: {
      data: base64Data,
      mimeType,
      fileName: `ai_image.${ext}`,
      fileExtension: ext
    }
  }
}];
